//		Exec(ctx)
func (_c *ShareCreateBulk) OnConflictColumns(columns ...string) *ShareUpsertBulk {
	_c.conflict = append(_c.conflict, sql.ConflictColumns(columns...))
	return &ShareUpsertBulk{
		create: _c,
	}
}

